  ('finatext', 'Finatext', 'Japan', 'Fintech', ARRAY['Backend Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['CrossFunctional'], ARRAY['Craftsmanship'], ARRAY['Collaboration','ProblemSolving'], ARRAY['Collaboration demonstrated in prior collaboration','ProblemSolving demonstrated in prior collaboration'], ARRAY['PoorQualityDiscipline'], ARRAY['Documentation'], '[Finatext hiring fallback summary] Finatext recruiting commonly emphasizes fintech product development, backend quality, regulatory awareness, and collaborative engineering Strong candidates can show secure service delivery, documentation habits, and practical problem solving in financial systems', 0.7, ARRAY['finatext-manual_fallback']),
