  ('kubell', 'kubell', 'Japan', 'Business Communication SaaS', ARRAY['Machine Learning Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['MissionAlignment'], ARRAY['Collaboration','ProductThinking'], ARRAY['Collaboration demonstrated in prior collaboration','ProductThinking demonstrated in prior collaboration'], ARRAY['LimitedCollaboration'], ARRAY[]::text[], '[採用情報 | 株式会社kubell（旧 Chatwork株式会社）] 人とテクノロジーをかけ合わせたBPaaSで、中小企業のDXを実現 国内最大級のビジネスチャット「Chatwork」を起点に、DXされた業務プロセスそのものをクラウド経由で提供するBPaaS事業を展開', 0.6000000000000001, ARRAY['kubell-cheerio']),
