  ('rakuten', 'Rakuten', 'Japan', 'Internet Platform', ARRAY['SRE / DevOps Engineer'], ARRAY['JavaScript','Go','Python','Java','Kotlin','Ruby','PHP'], ARRAY[]::text[], ARRAY[]::text[], ARRAY['GlobalTeam'], ARRAY[]::text[], ARRAY['Collaboration','LearningAgility','ProductThinking'], ARRAY['JavaScript proficiency in real product work','Go proficiency in real product work','Python proficiency in real product work','Java proficiency in real product work','Kotlin proficiency in real product work','Ruby proficiency in real product work','PHP proficiency in real product work','Collaboration demonstrated in prior collaboration','LearningAgility demonstrated in prior collaboration','ProductThinking demonstrated in prior collaboration'], ARRAY[]::text[], ARRAY['ProductDelivery','SystemDesign'], '[職種紹介 エンジニア (プロダクト開発含む)|楽天グループ株式会社] 高度な専門性を生かし、開発という枠にとらわれず、楽天サービスを進化させる プロジェクトマネージャー、プロダクトマネージャー、プログラムマネージャーなど', 0.7, ARRAY['rakuten-cheerio']),
  ('sansan', 'Sansan', 'Japan', 'B2B SaaS', ARRAY['Software Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], '誰もが利用するさまざまな道が、生活のインフラとして人々を支えています そんな道をつくるため、私たちはいつも、新しい出会いを楽しみにしています', 0.45, ARRAY['sansan-cheerio']),
  ('smartbank', 'SmartBank', 'Japan', 'Fintech', ARRAY['SRE / DevOps Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY['JapaneseBusiness'], ARRAY[]::text[], ARRAY['Transparency','Ownership'], ARRAY['Communication','Collaboration','Ownership','ProductThinking'], ARRAY['JapaneseBusiness communication readiness','Communication demonstrated in prior collaboration','Collaboration demonstrated in prior collaboration','Ownership demonstrated in prior collaboration','ProductThinking demonstrated in prior collaboration'], ARRAY['LowOwnership','WeakCommunication'], ARRAY['SystemDesign'], 'たくさんの人が毎日、熱狂的に使ってくれるようなサービスを生み出したい そういって週末に集まった3人が自然とWebサービスを作り出すようになり、会社をつくり、初めて生み出したヒット作が日本初のフリマアプリ「フリル」でした 今でも一切変わらず、イシューを解き、人々が本当に欲しかったモノを作り出すことで、世の中をより良くしていきたいと思っています', 0.7, ARRAY['smartbank-cheerio']),
  ('smarthr', 'SmartHR', 'Japan', 'HR SaaS', ARRAY['Software Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['MissionAlignment','Transparency'], ARRAY['Collaboration','LearningAgility','ProblemSolving','ProductThinking'], ARRAY['Collaboration demonstrated in prior collaboration','LearningAgility demonstrated in prior collaboration','ProblemSolving demonstrated in prior collaboration','ProductThinking demonstrated in prior collaboration'], ARRAY['AmbiguityHandling'], ARRAY[]::text[], '人は経験がないことにためらい、先の見えない道を進むことに臆する 私たちが向き合う“労働にまつわる社会課題”も、その一つひとつが未知への挑戦だ ミッションと目指す未来well-working労働にまつわる社会課題をなくし、誰もがその人らしく働ける社会をつくる', 0.55, ARRAY['smarthr-readability']),
  ('smartnews', 'SmartNews', 'Japan', 'News / Consumer Internet', ARRAY['Software Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['Remote','GlobalTeam'], ARRAY['MissionAlignment'], ARRAY['Collaboration','ProductThinking'], ARRAY['Collaboration demonstrated in prior collaboration','ProductThinking demonstrated in prior collaboration'], ARRAY['LimitedCollaboration'], ARRAY[]::text[], 'A global team united by a single mission 誰もが発信者となった現代社会において、私たちが日々読むことのできる情報の量は爆発的に増加しています 一つだけ確かなことは、それらすべての情報を読むことは決してできない、私たちは読むべき情報を日々選び取らなければならない、ということです', 0.6000000000000001, ARRAY['smartnews-cheerio']),
  ('spacemarket', 'Spacemarket', 'Japan', 'Marketplace', ARRAY['Software Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['CrossFunctional'], ARRAY['Speed','Ownership'], ARRAY['Collaboration','Ownership'], ARRAY['Collaboration demonstrated in prior collaboration','Ownership demonstrated in prior collaboration'], ARRAY['LowOwnership','LimitedCollaboration'], ARRAY[]::text[], '[Spacemarket hiring fallback summary] Spacemarket hiring content generally highlights marketplace product development, user empathy, ownership, and collaborative execution Good candidate evidence includes shipping user-facing features, balancing speed with reliability, and communicating across teams', 0.6000000000000001, ARRAY['spacemarket-manual_fallback']),
  ('stores', 'STORES', 'Japan', 'Commerce SaaS', ARRAY['Software Engineer'], ARRAY['Go','Ruby'], ARRAY[]::text[], ARRAY[]::text[], ARRAY['Remote','Onsite','FlexibleHours','CrossFunctional'], ARRAY['UserFocus'], ARRAY['Communication','Collaboration','LearningAgility','ProblemSolving','ProductThinking'], ARRAY['Go proficiency in real product work','Ruby proficiency in real product work','Communication demonstrated in prior collaboration','Collaboration demonstrated in prior collaboration','LearningAgility demonstrated in prior collaboration','ProblemSolving demonstrated in prior collaboration','ProductThinking demonstrated in prior collaboration'], ARRAY[]::text[], ARRAY['SystemDesign'], '採用サイトSTORES についてメンバーを知るカジュアル面談募集職種募集職種・エントリーこだわりや情熱、たのしみに駆動される経済をつくるこだわりや情熱、たのしみに駆動される経済をつくるscrollABOUT USお店のデジタル、まるっと STORES は、中小事業者の挑戦を支えるコンパウンド型スタートアップです 私たちが目指すのは、「こだわり」や「好き」が、きちんと価値になる社会', 0.7, ARRAY['stores-cheerio']),
  ('timee', 'Timee', 'Japan', 'HR Tech', ARRAY['Software Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['Speed','MissionAlignment'], ARRAY['Collaboration','LearningAgility'], ARRAY['Collaboration demonstrated in prior collaboration','LearningAgility demonstrated in prior collaboration'], ARRAY['AmbiguityHandling'], ARRAY[]::text[], 'タイミーは従来の仕組みや慣習にとらわれない新しい働き方を日本中にインストールし、 そんな社会の実現が潜在労働⼒を喚起するとともに、人材確保に悩む企業や地⽅⾃治体など、 圧倒的な事業成長の中で、我々は理想を掲げ実現することを諦めずに挑み続けます', 0.55, ARRAY['timee-cheerio']),
  ('ubie', 'Ubie', 'Japan', 'HealthTech', ARRAY['Machine Learning Engineer','SRE / DevOps Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['Remote','Onsite','FlexibleHours','CrossFunctional'], ARRAY['UserFocus','Craftsmanship','MissionAlignment','Transparency'], ARRAY['Collaboration','LearningAgility','ProductThinking'], ARRAY['Collaboration demonstrated in prior collaboration','LearningAgility demonstrated in prior collaboration','ProductThinking demonstrated in prior collaboration'], ARRAY['PoorQualityDiscipline'], ARRAY[]::text[], 'The Next Giant Leapfor the Human Race人類の次なる大きな飛躍を、あなたとともにSCROLL生成AI活用NEWカジュアル面談特設サイトはこちらkeyboard_arrow_rightPIVOTにて動画公開中代表 阿部から「健康寿命を延ばす医療とのマッチング改革」をテーマにお話してます launchAbout usMessage“ Ubieというスペースシャトルは、今まさに発射の時を迎えている ”私たちの使命は、世界80億人の健康寿命の延伸 さまざまな理由から最適な治療にたどりつけない患者さんが世界中にあふれている中で、医療×テクノロジーの可能性に全てを賭け、創業から6年で唯一無二の自動問診アルゴリズムとプラットフォームを作り上げてきました', 0.65, ARRAY['ubie-cheerio']),
  ('wantedly', 'Wantedly', 'Japan', 'HR Platform', ARRAY['Software Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY['UserFocus'], ARRAY['Collaboration','LearningAgility','ProductThinking'], ARRAY['Collaboration demonstrated in prior collaboration','LearningAgility demonstrated in prior collaboration','ProductThinking demonstrated in prior collaboration'], ARRAY[]::text[], ARRAY['GitHubPortfolio','ProductDelivery'], '究極の適材適所により、シゴトでココロオドルひとをふやす仕事 = 辛いという考え方がはびこっています 産業革命直後、人間が機械の延長として扱われていた時代はそうだったかもしれません しかしロボティックスやAIが発達した今、シゴトは生きる目的として、没頭できる対象になりつつあります', 0.6000000000000001, ARRAY['wantedly-readability']),
  ('zozo', 'ZOZO', 'Japan', 'E-commerce', ARRAY['Software Engineer'], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], ARRAY[]::text[], '私たちZOZOが大切にしている企業理念や経営戦略、サステナビリティステートメントなどをご紹介します ※株式会社Bloomが運営する「Bloomキャリア登録」サービスを利用しています NEW 「通販新聞」で販売促進企画担当者へのインタビュー記事が掲載されました', 0.45, ARRAY['zozo-readability'])
ON CONFLICT (company_id) DO NOTHING;

